var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. </color>","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。</color>","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. </color>","TWN":"知識<color=#ff3636>的饗宴</color>準備<color=#ff3636>好了。 </color>"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>연회는</color> 아직<b>인</b>가.","JPN":"<color=#ff3636>宴会は</color>まだ<b>なの</b>か。","ENG":"Wh<color=#ff3636>en shall th</color>e ba<b>nquet b</b>egin?","TWN":"<color=#ff3636>宴會</color>還沒<b>開始</b>嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"가, 가까이 오지 마! 가까이 오지 마!!","JPN":"く、来るな！　来るな！！","ENG":"G-get away from me! Get away from me!","TWN":"別…別過來！走開！！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이것들은 뭐야…… 이 괴물들은 다 뭐냐고……!","JPN":"こいつらはなんだ……この化け物たちは何なんだよ！","ENG":"What's all this…? What are these monsters doing here?!","TWN":"這些東西是怎樣……這些怪物到底都是些什麼……！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"흐음. 이 얼간이에게서 얻을 지식은 이걸로 끝인 것 같군.","JPN":"ふーん、この間抜けから得られる知識はこれで終わりのようだな。","ENG":"Hmm... Hmm. It seems this is all the knowledge the fool has to offer.","TWN":"嗯，似乎無法再從這傻瓜身上取得任何知識了。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"어서 제물을 바칠 의식을 준비해. <color=#ffd34c>호수</color>가 굶주려하는 간격이 더 짧아지고 있어.","JPN":"早く生贄を捧げる儀式の準備をしなさい。<color=#ffd34c>湖</color>が飢える間隔が短くなっているの。","ENG":"Prepare the sacrifice ritual with haste. The intervals between the <color=#ffd34c>Lake</color>'s hunger pangs keep growing shorter.","TWN":"快準備獻祭儀式吧。<color=#ffd34c>湖水</color>飢餓的週期越來越短了。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"그리고 다음부터는 더 요긴한 지식을 지닌 놈으로 선발하면 좋겠군.","JPN":"あと、次からはもう少し使える知識を持っている奴にしてちょうだい。","ENG":"And next time, I wish you'd bring someone with more useful knowledge.","TWN":"另外，我希望之後挑的人可以具備更重要的知識。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"살려 주세요! 살려만 주시면 뭐든 하겠습니다! 뭐든지요!","JPN":"助けてください！　助けてくだされば何でもやります！　なんでも！","ENG":"Please don't kill me! I'll do anything if you spare me! Anything!","TWN":"放過我吧！只要不殺我，我什麼都願意做，任何事！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"막노동할 사람은 안 필요하십니까? 쓰레기를 치울 사람은요! 뭐든지 제발 시켜 주세요!","JPN":"現場の作業員は必要ありませんか？　ゴミを片付ける人は？　お願いですから何でもやらせてください！","ENG":"Do you need anyone to do your chores? How about a janitor? Please, I'll do anything!","TWN":"需要壯丁嗎？還是幫你倒垃圾？拜託派事情給我做！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회장님. 실례지만 저 원숭이를 제물로 바치는 건 재고해 주시죠.","JPN":"学会長。失礼ですが、あの猿を生贄に捧げることは再考してください。","ENG":"Ms. President. If I may, please reconsider offering that animal as a sacrifice.","TWN":"會長，請恕我直言，用猴子獻祭一事還請三思。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"왜, 저런 무지한 것에게 미련이라도 남았나?","JPN":"なに、あの無知な者に未練でも残っているのか？","ENG":"Why? Are you somehow attached to that ignoramus?","TWN":"為何？你捨不得這個無知的東西嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맑은 호수에 오물을 버리는 몰상식한 행위와 다를 바 없기 때문이죠.","JPN":"清らかな湖に汚物を捨てる常識外れの行為と変わらないからです。","ENG":"It's only because this would be akin to adulterating a pristine lake with excrement.","TWN":"因為這無疑是把污染物扔進清澈湖水的無知行為。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"지금 같은 시기에 호수의 제물로 바쳐진다는 것은 저 원숭이에게 과분한 영광입니다.","JPN":"今のような時期に湖の生贄として捧げられるということは、あの猿にとって過分な光栄です。","ENG":"Becoming a sacrifice unto the Lake at a time like this is an honor far beyond what that animal deserves.","TWN":"就此刻而言，那隻猴子不配當作祭物獻給湖水。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"기관의 방해로 오래토록 이어진 허기를 달랠 제물이니, 더욱 엄선해야 하지 않겠습니까?","JPN":"機関の妨害で長く続いた空腹を満たすための生贄ですから、もっと厳選すべきではないでしょうか？","ENG":"The next sacrifice must satiate the prolonged hunger wrought by the Institution's interference. Surely we must curate a more worthy repast?","TWN":"因為這個祭物是要解決，因機關的阻礙而長久累積的飢餓，難道不該慎選嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"……그렇다면 나는 그 역겨운 버넷밖에 생각나지 않아.","JPN":"……それなら、代わりはあの鬱陶しいバーネットしか思い浮かばないのだが。","ENG":"…That only reminds me of that disgusting wretch, Burnett.","TWN":"……那我腦中想到的人選，就只有那個討厭的伯內特。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"버넷 경과 사적으로 몇 차례 불미스러운 사건이 있으셨다는 사실은 저도 잘 알고 있습니다.","JPN":"バーネット卿とはプライベートで何度か不祥事があったことは承知しています。","ENG":"I'm well aware that you've had several undesirable personal exchanges with Sir Burnett.","TWN":"我也知道會長和伯內特卿有些私人恩怨。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그의 사슬이 호수와 상극이라는 것 역시 말이죠.","JPN":"彼の鎖が湖と相克ということもです。","ENG":"And also that his chain is most formidably incompatible with the Lake.","TWN":"而且他的鐵鍊和湖水相剋也是事實。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"만족하실 만한 제물은 제가 물색해 오겠습니다, 학회장님. 부디 시간을 허락해 주시길.","JPN":"満足していただけそうな生贄は私が探してきます、学会長。どうか少しお時間をいただけますでしょうか。","ENG":"I assure you I shall procure a sacrifice more to your satisfaction, ma'am. If you'd so graciously grant me the time, that is.","TWN":"請會長再給我些時間，我會再物色讓您滿意的祭物的。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"허락해 주지. 하지만 저 자는 이미 우리 가문의 영지에 발을 들였어.","JPN":"いいだろう。だが、あの者はすでに当家の領地に足を踏み入れた。","ENG":"I'll allow it. But he has already set foot in our family's estate.","TWN":"好吧，但那個人已經踏入我們家族的領地。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"전통에 따라 방생은 허락되지 않아.","JPN":"伝統によって放生は許されない。","ENG":"Tradition dictates that no such trespasser shall be set free.","TWN":"根據傳統，我無法放生他。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"물론입니다. 이대로 내보내기에는 세상에 부끄러운 제자니까요.","JPN":"もちろんです。このまま送り出すには、とても恥ずかしい限りの弟子ですからね。","ENG":"Why, of course. It'd be far too embarrassing to release such a disgraceful pupil into the world in his current state.","TWN":"那是當然。就這樣放他走面子要往哪放。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"진즉부터 사용처를 생각하고 있었나 보군. 어떻게 써먹을 거지?","JPN":"前から使い道を考えていたようだな。何に使うつもりだ？","ENG":"So you've already devised another use for the wretch. Pray tell me, what shall you do with him?","TWN":"看來你早就已經有打算，你想怎麼做？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"자신의 목숨만 건질 수 있다면 죄책감 없이 남들을 수렁으로 밀어넣을 자입니다.","JPN":"自分の命さえ助かるならば、罪悪感なく他人を泥沼に落とす者です。","ENG":"The fellow will push others to their doom without remorse to save his own skin.","TWN":"他那個人只要能保住自己的命，就算推人入火坑也不痛不癢。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그러니…….","JPN":"ですので……","ENG":"Therefore…","TWN":"所以……"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"교양 있는 학회원이라면 거들떠도 안 볼 일을 맡겨야겠죠.","JPN":"教養のある学会員なら見向きもしない仕事を任せるべきでしょう。","ENG":"I would task him to an endeavor no sophisticated member of this Society would stoop to consider.","TWN":"就讓他去做那些高貴的學會成員都不屑一顧的事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"허억! 헉! 허억……!","JPN":"ハァッ、ハァ！　ハッ……!","ENG":"*Huff* *Gasp!* *Huff…!*","TWN":"咳咳！呼呼！咳咳咳……！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야? 왜 그래? 무슨 나쁜 꿈 꿨어?","JPN":"ダ、ダーリン？　どうしたの？　悪い夢でも見たの？","ENG":"B-babe? What's wrong? Did you have a scary dream?","TWN":"親…親愛的？你怎麼了？做惡夢嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Oh...","TWN":"沒……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아니야. 악몽을 좀 꿨어.","JPN":"大丈夫だ、ちょっと悪夢を見ただけだ。","ENG":"It's nothing. Just a nightmare.","TWN":"沒事，做惡夢而已。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"이런 멋진 곳에 휴가까지 와서? 사업 때문에 너무 스트레스 받는 거 아냐?","JPN":"こんな素敵な場所に休みに来たのに。仕事のせいでストレスが溜まりすぎたんじゃない？","ENG":"But we're on vacation in this paradise. You sure your business isn't stressing you out too much?","TWN":"來這麼棒的地方度假還做惡夢？是因為工作壓力太大嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"괜찮아. 사업을 하지 않았더라면 이렇게 자기랑 만날 수도 없었을 테니까.","JPN":"平気さ。仕事をしなかったら、こんな可愛い彼女に出会えなかったはずだからね。","ENG":"It's fine. I wouldn't be able to spend time with you in a place like this if it weren't for the business.","TWN":"我沒事，如果不是因為工作，我也不會認識親愛的。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"뭐야, 정말. 사람 많은 데서 그렇게 말하면 부끄럽잖아.","JPN":"もぉ～こんな人混みの中でそんなこと言われると照れちゃうわ。","ENG":"Aww, babe. You'll make me blush in front of all these people.","TWN":"你討厭～大家都在看，人家會害羞啦～"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래? 그러면 아예 이 호텔도 전세 낼까?","JPN":"そうかい？　じゃあ、このホテルを丸ごと貸し切りにしようか？","ENG":"Is that right? Then how about we rent out the whole hotel?","TWN":"是喔？那還是乾脆我把飯店包下來？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"또 그러네. 나 때문에 그렇게 돈 많이 쓰지 말라니까.","JPN":"またまた、あたしのために大金を使う必要はないよ。","ENG":"There you go again. I told you, you should stop spoiling me.","TWN":"你又來～人家不想你為人家花那麼多錢嘛～"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"아 참. 회사에서 전화 왔어. 받아 봐.","JPN":"そうだ、会社からの電話よ。出てみて。","ENG":"Oh, by the way… You got a call from the company. You should take it.","TWN":"對了，公司打電話來找你。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아, 자기는 먼저 해변으로 가 있어. 금방 얘기 마치고 따라갈게.","JPN":"ああ、先にビーチに行ってくれ。終わったら向かうよ。","ENG":"Go ahead and hit the beach, sweetheart. I'll catch up with you right away.","TWN":"親愛的，你先去海邊等我，我談完馬上就過去找你。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"무리하면 안 돼? 약속이야?","JPN":"無理しちゃダメよ？　約束よ？","ENG":"Don't push yourself too hard, okay? Promise?","TWN":"不要太勉強自己喔！打勾勾？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭐냐, 셰나. 휴식 중이니 연락은 되도록 하지 말라고 했을 텐데.","JPN":"なんだ、シェナ。休暇中はなるべく連絡を控えるようにと言ったはずだが。","ENG":"This better be good, Shena. I told you not to bother me on vacation unless it was absolutely necessary.","TWN":"搞什麼，世娜！我不是說過，休假期間盡量不要吵我嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"미안, 대표님. 그렇지만 대표님이 요구했던 일이라 나도 어쩔 수 없었는걸.","JPN":"ごめんね、代表。でも代表に頼まれたことだし仕方なかったのよ。","ENG":"Sorry, boss. But this was something you asked for, so I had no choice.","TWN":"抱歉，BOSS。但這是您的要求，我也沒辦法。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"요구? 혹시 코핀 컴퍼니 건인가?","JPN":"頼まれた？　もしかしてコフィンカンパニーの件か？","ENG":"Something I asked for? Does it have to do with the Coffin Company?","TWN":"我的要求？是科芬公司的事嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"정답이야. 안 잊어 버리고 있었네.","JPN":"正解。忘れてなかったわね。","ENG":"Bingo. So you didn't forget.","TWN":"賓果！你還記得嘛！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"당연하지. 그것들만큼 일을 귀찮게 만든 놈들은 여지껏 없었으니까.","JPN":"当然だ。あいつらほど手こずらせる連中は今までいなかったからな。","ENG":"Of course not. No one made my life painful more than those scumbags.","TWN":"那當然，我還沒遇過像他們那麼會找麻煩的傢伙。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"정규 태스크포스 컴퍼니라 잘못 건드렸다간 관리국에 조금 밉보이긴 할 거야.","JPN":"正規のタスクフォースカンパニーだから、下手に手を出したら管理局に目をつけられるわよ。","ENG":"They are an official TASKFORCE Company, so you might tick off the Administration a bit if you mess with them.","TWN":"畢竟是正式的特遣勢力公司，萬一一個弄不好可是會得罪管理局的。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭐, 나야 하란 대로 해야 되는 처지니 어쩔 수 없지만.","JPN":"まあ、私は言われたとおりにしないといけない立場だから仕方ないけど。","ENG":"Though I guess I have no choice but to do as I'm told.","TWN":"不過，反正我是領人家薪水的，也是身不由己。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"어디……. 보고서만 봐선 별로 대단할 것도 없는 회사군.","JPN":"どれ……報告書だけなら別に大したこともない会社だな。","ENG":"Let's see… Based on this report, there's really nothing special about them.","TWN":"我看看……從報告看來，也不是什麼多厲害的公司嘛！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"꼴에 태스크포스라고 카운터는 몇 놈 있나? 개량형 강화복의 좋은 테스트베드가 되겠어.","JPN":"タスクフォースカンパニーといってもカウンターはどうせ数人程度だろ？　改良型強化服の良いテストベッドになりそうだな。","ENG":"Hmph, I guess they've got a handful of Counters though, being a TASKFORCE and all. They'll provide an excellent testbed for the upgraded power suit.","TWN":"說是特遣勢力，是有幾個制裁者？或許可以成為改良型強化服不錯的測試台？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄? 회사 규모만 보고 단정 짓지는 않는 편이 좋을걸?","JPN":"どうかしら？　会社の規模だけみて断定するのはよくないと思うけど？","ENG":"I wouldn't be so sure. You might not want to let their size fool you.","TWN":"不知道欸？不過光看公司規模就輕易下斷言，應該不太好吧？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"연구소에 침입했던 애들 중에는 그 불량품 A타입도 있었거든.","JPN":"研究所に侵入した子の中に、あの不良品のAタイプもいたの。","ENG":"One of the infiltrators to the lab included the Defect Type A.","TWN":"那個A型瑕疵品也在入侵研究所的傢伙之中。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"기껏 카운터로 각성해 놓고 그 구 관리국인가 하는 것들한테 붙었다던 복제인간 말이지.","JPN":"せっかくカウンターに覚醒しておいて、あの旧管理局とやらについたクローン人間のことか。","ENG":"You mean that clone who got her Counter powers only to end up siding with the so-called Old Administration?","TWN":"你是說那個覺醒成制裁者後，投靠舊管理局的複製人嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"코핀 컴퍼니를 공격할 때 그 복제인간은 우리 측 실험체들과 같이 사로잡아 와라.","JPN":"コフィンカンパニーを攻撃する際、そのクローン人間をうちの実験体と一緒に捕らえてくるように。","ENG":"When you attack the Coffin Company, be sure to capture that clone alive, along with our test subjects.","TWN":"攻擊科芬公司時，把那個複製人和實驗體都給我抓回來！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내 연구소를 엉망으로 만든 대가가 뭔지 알려 줘야겠어.","JPN":"僕の研究所をめちゃくちゃにしやがった代償がどれぐらいか、思い知らせてやらねば。","ENG":"I'll teach them a lesson for wrecking my lab.","TWN":"我要讓她知道，毀掉我的實驗室要付出什麼代價！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아하, 결정하기 전에 지금 전송해 준 것부터 확인해 봐.","JPN":"なるほどね、でもその前に今転送したものを確認してみて。","ENG":"Oh, before you make up your mind, check out what I just sent you.","TWN":"哈哈，你先看一下我傳給你的東西再說吧。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"……뭐야, 이 사진들은? 도촬에 취미라도 있었나?","JPN":"……なんだ、この写真は？　盗撮の趣味でもあったのか？","ENG":"What's with these photos? You into voyeurism?","TWN":"……這些照片是？你的興趣是偷拍喔？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"으흠, 전혀. 난 마음에 드는 애는 내버려 두지 않고 관객으로 앉혀 두는 편이거든.","JPN":"いいえ、全然。私は、気に入った子は必ず観客にする性格だからね。","ENG":"Uh, not at all. I prefer to keep people I fancy in the audience, rather than stalking them.","TWN":"才不是咧，如果遇到喜歡的人，我會緊緊抓住他，讓他成為我的座上賓。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그건 코핀 컴퍼니와 접촉한 인물들을 정리한 자료야. <color=#ffd34c>교수님</color>이 수고해 줬지.","JPN":"あのコフィンカンパニーと接触した人物をまとめた資料よ。<color=#ffd34c>教授</color>がまあまあ頑張ってくれたわ。","ENG":"That's a dossier on folks who've been in contact with the Coffin Company. Courtesy of <color=#ffd34c>the Professor</color>.","TWN":"照片裡都是和科芬公司接觸過的人。真是辛苦<color=#ffd34c>教授</color>了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"칫…… 그 망할 늙은이가…… 응?","JPN":"ちっ……あのうざい老いぼれが……うん？","ENG":"Hmph… That old fool… Huh?","TWN":"嗟…… 那個老傢伙……嗯？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"잠깐, 이 녀석은……","JPN":"まて、こいつは……","ENG":"Hang on, isn't this…","TWN":"等等，這個傢伙是……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아냐. 그럴 리가 없어. 분명 이면세계에서 뒈졌어야 하는데…….","JPN":"いや、そんなはずがない。確かに裏世界でくたばったはずだが……","ENG":"No. It can't be. I could've sworn the little bxxch kicked the bucket in the Counterside…","TWN":"不，不可能！不是死在異界嗎……."},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아하. 바른 말 고운 말 쓰셔야죠, 대표님.","JPN":"ちょっと。汚い言葉はだめよ、代表。","ENG":"Woah, there. You kiss your mother with that mouth?","TWN":"嘿，BOSS，你這樣說沒人聽得懂喔。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이 사진!","JPN":"この写真！","ENG":"This photo!","TWN":"這張照片！"},"stage":{"bg":"SS_SHADOW_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이 사진이 그라운드 원에서 찍혔다고? 이 사진 속 여자애가 코핀 컴퍼니와 접촉했다고?","JPN":"この写真がグラウンド・ワンで撮られたものだと？　この写真の女がコフィンカンパニーと接触したのか！？","ENG":"You're saying this was taken at Ground One? The girl in this photo has been in contact with Coffin Company?","TWN":"這張照片是在G1拍到的嗎？照片裡的女生也有和科芬公司接觸過？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"나한테 왜 그래. 혹시나 보면 알려 달라고 자기가 말했으면서.","JPN":"私に聞かれてもね。もし見つかったら教えてほしいって言ったのは代表でしょ？","ENG":"What are you yelling at me for? You're the one who told me to let you know if I see her.","TWN":"幹嘛問我？是你說如果有看到就告訴你的。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"반응을 보니 우리 대표님이 찾던 사람이 맞나 봐? 그치?","JPN":"その反応だと、代表が探していた人みたいね？","ENG":"I take it that this is the person you've been looking for, huh? It is, right?","TWN":"看你的反應，她應該就是你要找的人吧？我說的沒錯吧？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그랬군. 이제야 앞뒤가 들어맞아.","JPN":"そうか。やっと辻褄が合った。","ENG":"I see… It all makes sense now.","TWN":"原來如此，這樣前後才連得起來。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호라이즌…… 이 빌어먹을 계집애가……","JPN":"ホライズン……あのクソ女……","ENG":"Horizon… That little brat…","TWN":"地平線…… 這該死的丫頭……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"무슨 소리야? 혼자만 아는 얘기 하지 말고 나한테도 좀 알려 주지 그래?","JPN":"どういうこと？　面白そうなエピソードがあるなら私にも教えてよ。","ENG":"What are you talking about? Why don't you stop brooding and let me in on whatever this is?","TWN":"你到底在說什麼？不要只說給自己聽，也說給我聽嘛～"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이 계집애가!!","JPN":"あのクソ女が！","ENG":"That little bxxch!","TWN":"這個丫頭！！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이 사람 행세 하는 빌어먹을 고철 로봇이 코핀 컴퍼니를 사주했던 거야!","JPN":"人のフリをするこの鉄くずがコフィンカンパニーをそそのかしたんだ！","ENG":"That junk-metal wannabe Pinocchio sicced the Coffin Company on me!","TWN":"明明是個破爛機器人，裝得一副人模人樣，還唆使科芬公司！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 내가 온갖 역경을 딛고 출세한 게 그렇게나 못마땅했나 보군…….","JPN":"そうか、僕があらゆる逆境を乗り越えて出世したのがそんなに気に食わなかったんだな……","ENG":"She must have gone crazy with envy that I overcame all my trials and became so successful…","TWN":"怎樣！我關關難過關關過，好不容易才闖出一片天，是有這麼礙她的眼嗎……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래서 내 실험체를 빼돌리고도 모자라, 연구소까지 폐쇄하게 만들어?","JPN":"だから僕の実験体を盗んだうえに、研究所まで壊したのか？","ENG":"And just because of that, she not only stole my test subjects but made me shut down my lab?!","TWN":"偷走我的實驗體不打緊，還要毀掉研究所？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"순순히 당해 줄 것 같냐! 카운터들도 다 뒈졌는데 고물 사채업자 나부랭이가 어디서 감히!!","JPN":"黙ってやられるものか！　カウンターどもも全員くたばったってのに、鉄くずの闇金業者ごときが調子に乗りやがって！！","ENG":"You think I'd go down that easy?! All your Counters are dead! You got nothing on me, you loan shark piece of junk!","TWN":"以為我會乖乖逆來順受嗎？連制裁者我都可以弄死，區區的破爛高利貸敢弄我？！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"계획을 바꾼다. 준비된 타격조를 당장 이 계집애가 있는 곳으로 보내.","JPN":"計画を変える。出動準備を済ませた突撃隊を今すぐこ小娘のところに送れ。","ENG":"Change of plans. Send in a strike team to wherever this little brat is right now.","TWN":"計畫改變！立刻把準備好的攻擊組，派到那丫頭所在的地方！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"어디 있는지 조사는 끝내 뒀겠지?","JPN":"どこにいるかは知ってんだろうな？","ENG":"You've already located her, right?","TWN":"應該已經查到她在哪裡吧？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"제 6 난민지구. 엘릭서 복원 운운하던 덜떨어진 사기꾼을 처박아 둔 곳이야.","JPN":"第6難民地区。エリクサーを復元するとか言ってた間抜けな詐欺師集団を放り捨てた場所よ。","ENG":"The 6th refugee district. It's where we stashed that stupid swindler who won't shut up about restoring the Elixir.","TWN":"在第6難民區。就是一直說要重現聖水的騙子所在的地方。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"연구가 잘 진행되나 확인하는 김에 목을 따 올까?","JPN":"研究の進捗確認を兼ねて、首でも取ってこようか？","ENG":"Want us to bring you her head while we go check on the research progress?","TWN":"要我去確認一下研究進度，順便把她的人頭摘回來嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아니. 죽이지 말고 내 앞에 끌고 와라.","JPN":"いや、生きたまま僕の目の前に連れて来い。","ENG":"No. Bring her alive.","TWN":"不，給我活捉她！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"돈에 미쳐서 내 인생을 꼬이게 만든 계집애한테…… 복수해 줘야 하니까.","JPN":"金に狂って僕の人生をこじらせたクソ女に……復讐するためにな。","ENG":"I'm going to personally take revenge on that deranged moneygrubber for ruining my life.","TWN":"愛錢愛到毀掉我的人生……我一定要向那丫頭報仇！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};